-- Complete truncated gear/focus descriptions (PHB 2024 PT-BR)
-- Generated by scripts/generate-gear-descriptions-seed.js — review before apply

UPDATE rpg.phb_item AS i
SET description = v.description
FROM (VALUES
  ('acido', $d$Ao executar a ação Atacar, você pode substituir um de seus ataques por arremessar um frasco de Ácido. O alvo deve estar a até 6 metros de você. Em um acerto, o alvo sofre 2d6 de dano de Ácido.$d$),
  ('agua-benta', $d$Ao executar a ação Atacar, você pode substituir um de seus ataques por arremessar um frasco de Água Benta. O alvo deve estar a até 6 metros de você. Em um acerto, o alvo sofre 2d6 de dano Radiante se for um Demônio ou um Morto-vivo.$d$),
  ('algibeira', $d$Uma Algibeira comporta até 3 kg em um volume de 6 litros.$d$),
  ('antitoxina', $d$Como uma Ação Bônus, você pode beber um frasco de Antitoxina para obter Vantagem em salvaguardas de Constituição para evitar ou encerrar a condição Envenenado por 1 hora.$d$),
  ('apito-sinalizador', $d$Quando soprado como uma ação Usar Objeto, um Apito Sinalizador emite um som audível a até 180 metros.$d$),
  ('ariete-portavel', $d$Você pode usar um Aríete Portátil para arrombar portas. Ao fazê-lo, você tem Vantagem no teste de Força (Atletismo). Se outro personagem ajudar, você também pode adicionar o modificador de Força dele ao teste.$d$),
  ('armadilha-de-caca', $d$Como uma ação Usar Objeto, você pode armar uma Armadilha de Caça. Quando uma criatura Pequena ou maior pisa na armadilha, deve ser bem-sucedida em uma salvaguarda de Destreza CD 13 ou sofrer 1d4 de dano Perfurante e ter seu Deslocamento reduzido a 0 enquanto permanecer na armadilha. Como uma ação, a criatura ou outra adjacente pode fazer um teste de Força CD 13 para liberá-la.$d$),
  ('arpeu', $d$Como uma ação Usar Objeto, você pode arremessar um Arpéu a até 15 metros, fazendo um teste de Destreza (Acrobacia) ou Força (Atletismo) CD 13. Em um sucesso, o gancho prende em uma superfície ou objeto ao alcance; você pode então escalar a corda anexada.$d$),
  ('baliza', $d$Uma Baliza tem 3 metros de comprimento. Você pode usá-la como uma arma improvisada (1d4 Contundente) ou para marcar uma rota.$d$),
  ('barril', $d$Um Barril armazena até 160 litros de líquido ou até 180 kg de material sólido.$d$),
  ('bau', $d$Um Baú armazena até 0,35 metros cúbicos (ou cerca de 150 kg) de conteúdo.$d$),
  ('bolsa-de-componentes', $d$Uma Bolsa de Componentes é à prova d'água e cheia de compartimentos para armazenar todos os componentes materiais e outros itens especiais de que você precisa para conjurar suas magias, exceto aqueles que têm um custo especificado (conforme indicado na descrição de uma magia).$d$),
  ('cadeado', $d$Um Cadeado vem com uma chave. Sem a chave, uma criatura proficiente com Ferramentas de Ladrão pode abrir o cadeado com um teste bem-sucedido de Destreza (Ferramentas de Ladrão) CD 15.$d$),
  ('caixa-para-fogo', $d$Uma Caixa para Fogo é um pequeno recipiente contendo pedra de sílex, aço contra fogo e material muito inflamável (isca). Usá-la para acender uma tocha — ou qualquer outra coisa exposta a condições climáticas ordinárias — leva 1 Ação Bônus.$d$),
  ('cantil-cheio', $d$Um Cantil comporta até 2 litros. Se você não beber água ao longo de um dia, corre o risco de Exaustão por sede (conforme as regras de privação).$d$),
  ('cobertor', $d$Enquanto estiver envolto em um cobertor, você tem Vantagem em salvaguardas de Constituição feitas para resistir aos efeitos do frio extremo.$d$),
  ('corda', $d$Como uma ação Usar Objeto, você pode dar um nó em uma Corda ou usá-la para amarrar uma criatura Incapacitada, Imóvel ou Disposta. Se a criatura tentar escapar, ela deve ser bem-sucedida em um teste de Força (Atletismo) ou Destreza (Acrobacia) CD 10. Você pode amarrar um objeto; arrebentar a corda exige um teste de Força CD 20.$d$),
  ('cordao', $d$Um cordão tem 3 metros de comprimento. Você pode usá-lo para amarrar objetos leves ou como componente improvisado.$d$),
  ('corrente', $d$Como uma ação Usar Objeto, você pode enrolar uma Corrente em torno de uma criatura Grande ou menor que esteja a até 1,5 metro de você, desde que a criatura tenha a condição Agarrado, Incapacitado ou Disposto. A criatura fica Restringida até escapar (teste de Força CD 20) ou até a corrente ser removida.$d$),
  ('escada', $d$Uma Escada tem 3 metros de altura. Você deve escalá-la para subir ou descer; trata-se de terreno difícil ao escalar.$d$),
  ('esferas-de-metal', $d$Como uma ação Usar Objeto, você pode derramar essas minúsculas esferas de metal de seu saco para cobrir uma área de 3 metros quadrados. Uma criatura que se mova sobre a área deve ser bem-sucedida em uma salvaguarda de Destreza CD 10 ou cair Prone. Leva 1 minuto para recolher as esferas.$d$),
  ('espelho', $d$Um espelho de aço portátil é prático tanto para uso pessoal quanto para olhar ao redor de cantos ou refletir luz.$d$),
  ('estacas-de-ferro', $d$Estacas de Ferro vêm em pacotes de dez. Como uma ação Usar Objeto, você pode cravar uma estaca em madeira, terra ou material semelhante.$d$),
  ('estojo-mapa-ou-pergaminho', $d$Um Estojo de Mapa ou Pergaminho armazena até 10 folhas de papel ou 5 de pergaminho sem dobrá-las.$d$),
  ('estojo-virote-de-besta', $d$Um Estojo de Virotes de Besta armazena até 20 Virotes.$d$),
  ('estrepes', $d$Como uma ação Usar Objeto, você pode espalhar um saco de Estrepes para cobrir uma área de 1,5 metro quadrado. Qualquer criatura que entrar na área deve ser bem-sucedida em uma salvaguarda de Destreza CD 15 ou parar de se mover e sofrer 1 de dano Perfurante. Até que a criatura recupere pelo menos 1 Ponto de Vida, seu Deslocamento de Caminhada é reduzido em 3 metros. Leva 1 minuto para recolher os estrepes.$d$),
  ('foco-arcano', $d$Um Foco Arcano assume uma das formas na tabela Foco Arcano e é um item especial — orbe, cristal, bastão, cajado especialmente construído, varinha ou objeto semelhante — projetado para canalizar o poder de magias arcanas. Um Feiticeiro, Bruxo ou Mago pode usar esse item como Foco de Conjuração.$d$),
  ('foco-druidico', $d$Um Foco Druídico assume uma das formas apresentadas na tabela Foco Druídico e é esculpido, amarrado ou forjado para canalizar magia da natureza. Um Druida ou Patrulheiro pode usar esse item como Foco de Conjuração.$d$),
  ('fogo-alquimico', $d$Ao executar a ação Atacar, você pode substituir um de seus ataques por arremessar um frasco de Fogo Alquímico. O alvo deve estar a até 6 metros de você. Em um acerto, o alvo começa a queimar: sofre 1d4 de dano de Fogo no início de cada um de seus turnos. Uma criatura pode encerrar esse dano usando sua ação para apagar as chamas com um teste de Destreza CD 10.$d$),
  ('grilhoes', $d$Como uma ação Usar Objeto, você pode usar Grilhões para algemar uma criatura Pequena ou Média Incapacitada. As criaturas algemadas têm a condição Restringido, e a condição termina se a fechadura for aberta (chave ou teste de Destreza com Ferramentas de Ladrão CD 20) ou arrebentada (teste de Força CD 20).$d$),
  ('kit-de-artista', $d$Um Kit de Artista contém os seguintes itens: [[caixa-para-fogo|Caixa para Fogo]], [[cantil-cheio|Cantil]], [[corda|Corda]], [[lanterna-coberta|Lanterna Coberta]], 10 dias de [[racoes|Rações]], [[saco-de-dormir|Saco de Dormir]], [[tenda|Tenda]] e 10 [[tocha|Tochas]].$d$),
  ('kit-de-assaltante', $d$Um Kit de Assaltante contém os seguintes itens: [[caixa-para-fogo|Caixa para Fogo]], [[corda|Corda]], [[pe-de-cabra|Pé de Cabra]], Capuz Escuro, 10 [[estacas-de-ferro|Estacas de Ferro]], [[lanterna-coberta|Lanterna Coberta]], 10 dias de [[racoes|Rações]], [[saco-de-dormir|Saco de Dormir]] e 10 [[tocha|Tochas]].$d$),
  ('kit-de-aventureiro', $d$Um Kit de Aventureiro contém os seguintes itens: [[caixa-para-fogo|Caixa para Fogo]], [[cantil-cheio|Cantil]], [[corda|Corda]], [[mochila|Mochila]], 2 potes de [[oleo|Óleo]], 10 dias de [[racoes|Rações]], [[saco-de-dormir|Saco de Dormir]], [[tenda|Tenda]] e 10 [[tocha|Tochas]].$d$),
  ('kit-de-curandeiro', $d$Um Kit de Curandeiro tem dez usos. Como uma ação, você pode gastar um uso do kit para estabilizar uma criatura com 0 Pontos de Vida que não esteja morta, sem precisar fazer um teste de Sabedoria (Medicina).$d$),
  ('kit-de-diplomata', $d$Um Kit de Diplomata contém os seguintes itens: [[bau|Baú]], 2 [[estojo-mapa-ou-pergaminho|Estojo de Mapa ou Pergaminho]], [[roupas-finas|Roupas Finas]], [[tinta|Tinta]], [[caneta-tinteiro|Caneta Tinteiro]], [[lampada|Lâmpada]], 2 potes de [[oleo|Óleo]], 5 folhas de [[papel|Papel]], frasco de [[perfume|Perfume]] e Selo de Cera.$d$),
  ('kit-de-erudito', $d$Um Kit de Erudito contém os seguintes itens: [[caixa-para-fogo|Caixa para Fogo]], [[livro|Livro]] de estudo, [[tinta|Tinta]], [[caneta-tinteiro|Caneta Tinteiro]], [[lanterna-coberta|Lanterna]], 10 folhas de [[pergaminho|Pergaminho]], [[saco-de-dormir|Saco de Dormir]] e 10 [[tocha|Tochas]].$d$),
  ('kit-de-escalada', $d$Um Kit de Escalada inclui arnês, luvas, pítons e ponteiras de bota. Como uma ação Usar Objeto, você pode usar o kit para ancorar-se; até se soltar (ação), você não pode cair mais de 7,5 metros a partir do ponto de ancoragem, e tem Vantagem em testes de Força (Atletismo) feitos para escalar.$d$),
  ('kit-de-explorador-de-masmorras', $d$Um Kit de Explorador de Masmorras contém os seguintes itens: [[caixa-para-fogo|Caixa para Fogo]], [[cantil-cheio|Cantil]], [[corda|Corda]], [[pe-de-cabra|Pé de Cabra]], [[light-hammer|Martelo]], 10 [[estacas-de-ferro|Estacas de Ferro]], 10 dias de [[racoes|Rações]], [[saco-de-dormir|Saco de Dormir]] e 10 [[tocha|Tochas]].$d$),
  ('kit-de-sacerdote', $d$Um Kit de Sacerdote contém os seguintes itens: [[agua-benta|Água Benta]], [[caixa-para-fogo|Caixa para Fogo]], [[cobertor|Cobertor]], [[cantil-cheio|Cantil]], 10 [[vela|Velas]], Roupas de Acólito, 2 [[estojo-mapa-ou-pergaminho|Estojo de Mapa ou Pergaminho]], [[saco-de-dormir|Saco de Dormir]], 10 dias de [[racoes|Rações]] e [[simbolo-sagrado|Símbolo Sagrado]].$d$),
  ('lampada', $d$Uma Lâmpada usa Óleo para combustão para emitir Luz Plena em um raio de 4,5 metros e Penumbra por mais 9 metros.$d$),
  ('lanterna-coberta', $d$Uma Lanterna Coberta usa Óleo para combustão para emitir Luz Plena em um raio de 9 metros e Penumbra por mais 9 metros. Como uma Ação Bônus, você pode abaixar a cobertura, reduzindo a luz a Penumbra em um raio de 1,5 metro.$d$),
  ('lanterna-foca-facho', $d$Uma Lanterna Foca-Facho usa Óleo como combustão para emitir Luz Plena em um cone de 18 metros e Penumbra por mais 18 metros.$d$),
  ('livro', $d$Um livro contém texto de ficção ou não-ficção. Se você consultar um livro enquanto faz um teste de Inteligência (História ou outro conhecimento relevante ao conteúdo), você tem Vantagem no teste, desde que o livro trate do assunto.$d$),
  ('luneta', $d$Objetos vistos através de uma Luneta são ampliados até o dobro do tamanho.$d$),
  ('lupa', $d$Uma Lupa concede Vantagem em qualquer teste de Inteligência (Investigação) feito para inspecionar um objeto a até 30 centímetros dela. Acender um fogo com uma lupa exige luz solar e cerca de 5 minutos.$d$),
  ('mapa', $d$Se consultar um mapa detalhado, você obtém um senso geral da geografia da região representada e pode evitar se perder enquanto seguir as rotas nele marcadas.$d$),
  ('mochila', $d$Uma Mochila armazena até 15 quilos dentro de 30 litros de volume.$d$),
  ('municao', $d$Munição é exigida por uma arma que tenha a propriedade Munição. A descrição de uma arma detalha o tipo de munição que ela usa. Comprar munição inclui o estojo ou aljava adequados.$d$),
  ('oleo', $d$Você pode cobrir uma criatura, objeto ou área com óleo usando uma ação Usar Objeto. Se aceso, o óleo queima por 2 rodadas e causa 5 de dano de Fogo à criatura ou objeto no início do turno da criatura ou quando um objeto é tocado pelas chamas. Uma área de 1,5 metro quadrada coberta por óleo é terreno difícil e, se acesa, causa 5 de dano de Fogo a cada criatura que entrar nela ou terminar o turno ali.$d$),
  ('pa', $d$Trabalhando por 1 hora, você pode usar uma Pá para cavar um buraco de 1,5 metro cúbico em solo solto, ou o dobro disso com ajuda.$d$),
  ('pe-de-cabra', $d$Usar um Pé de Cabra concede a você Vantagem em testes de Força nos quais a alavanca do pé de cabra possa ser aplicada.$d$),
  ('perfume', $d$O perfume vem em um frasco de 120 mililitros. Por 1 hora após aplicado, você tem Vantagem em testes de Carisma (Persuasão) feitos para influenciar humanoides que possam sentir o aroma — a critério do Mestre.$d$),
  ('pergaminho', $d$Uma folha de pergaminho pode comportar cerca de 250 palavras escritas à mão.$d$),
  ('pergaminho-magico-1-circulo', $d$Um Pergaminho Mágico contém a magia de 1º círculo escrita nele. Usá-lo segue as regras de pergaminhos mágicos do PHB.$d$),
  ('pergaminho-magico-truque', $d$Um Pergaminho Mágico contém um Truque escrito nele. Usá-lo segue as regras de pergaminhos mágicos do PHB.$d$),
  ('pocao-de-cura', $d$Esta poção é um item mágico. Como uma Ação Bônus, você pode beber a poção ou administrá-la a outra criatura, recuperando 2d4 + 2 Pontos de Vida.$d$),
  ('racoes', $d$As rações consistem em alimentos prontos para viagem, incluindo biscoito duro, carne seca, frutas secas e nozes. Um dia de rações alimenta uma criatura Média por um dia.$d$),
  ('rede', $d$Ao executar a ação Atacar, você pode substituir um de seus ataques por arremessar uma Rede. O alvo deve estar a até 4,5 metros e ser Grande ou menor. Em um acerto, o alvo tem a condição Restringido até escapar (ação: teste de Força CD 10) ou até a rede ser destruída (CA 10, 5 PV, imune a dano Contundente/Psíquico/Veneno).$d$),
  ('roldana-e-polias', $d$Roldana e Polias permitem içar até quatro vezes o peso que você normalmente conseguiria levantar, quando o sistema está devidamente instalado.$d$),
  ('roupas-fantasia', $d$Roupas de Fantasia incluem um traje elaborado e, muitas vezes, uma máscara. Úteis para disfarces e apresentações.$d$),
  ('roupas-finas', $d$Roupas Finas são feitas de tecidos caros e adornadas. Adequadas a cortes, banquetes e ambientes de alta sociedade.$d$),
  ('roupas-viagem', $d$Roupas de Viagem são roupas resistentes projetadas para o caminho: botas, capas e tecido que suportam o uso prolongado.$d$),
  ('saco-de-dormir', $d$Um Saco de Dormir acomoda uma criatura Pequena ou Média. Em clima frio, oferece o conforto básico para um descanso.$d$),
  ('simbolo-sagrado', $d$Um Símbolo Sagrado assume uma das formas na tabela Símbolo Sagrado — amuleto, emblema ou relicário — e é um item sagrado. Um Clérigo ou Paladino pode usá-lo como Foco de Conjuração.$d$),
  ('sino', $d$Quando tocado como uma ação Usar Objeto, um Sino produz um som claro audível a até 60 metros.$d$),
  ('tenda', $d$Uma Tenda acomoda para dormir até duas criaturas Médias, ou uma criatura e seu equipamento.$d$),
  ('tinta', $d$A tinta vem em uma garrafa de 30 mililitros, que fornece tinta suficiente para escrever cerca de 50 páginas.$d$),
  ('tocha', $d$Uma Tocha entra em combustão por 1 hora, emitindo Luz Plena em um raio de 6 metros e Penumbra por mais 6 metros. Se você realizar um ataque corpo a corpo com uma tocha acesa e acertar, o alvo sofre 1 de dano de Fogo.$d$),
  ('vela', $d$Por 1 hora, uma Vela acesa emite Luz Plena em um raio de 1,5 metro e Penumbra por mais 1,5 metro.$d$),
  ('veneno-basico', $d$Como uma Ação Bônus, você pode usar um frasco de Veneno Básico para aplicar o veneno a uma arma ou a até três peças de munição. Uma criatura atingida pela arma ou munição envenenada deve ser bem-sucedida em uma salvaguarda de Constituição CD 10 ou sofrer 1d4 de dano de Veneno. Uma vez aplicado, o veneno retém a potência por 1 minuto ou até causar dano.$d$)
) AS v(slug, description)
WHERE i.slug = v.slug;
